mapper.update:
UPDATE equipment
SET equipment_name = #{equipmentName},
    equipment_location = #{equipmentLocation},
    equipment_status   = #{equipmentStatus},
    equipment_message  = #{equipmentMessage}
WHERE equipment_id = #{equipmentId}

mapper.select:
SELECT equipment_id, equipment_name, equipment_location, equipment_status, equipment_message FROM equipment
AND ( CAST(equipment_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR equipment_name LIKE CONCAT('%', #{keyword}, '%') )
AND equipment_location LIKE CONCAT('%', #{location}, '%')
AND equipment_status = #{status}
ORDER BY equipment_id ASC LIMIT #{offset}, #{pageSize}
